import{_ as d,o as e,c as r,a2 as o}from"./chunks/framework.DeNJmwJc.js";const b=JSON.parse('{"title":"Chapter 65 — Cheat Sheet","description":"","frontmatter":{},"headers":[],"relativePath":"chapters/65-cheat-sheet.md","filePath":"chapters/65-cheat-sheet.md"}'),a={name:"chapters/65-cheat-sheet.md"};function c(n,t,i,h,s,l){return e(),r("div",null,[...t[0]||(t[0]=[o('<h1 id="chapter-65-—-cheat-sheet" tabindex="-1">Chapter 65 — Cheat Sheet <a class="header-anchor" href="#chapter-65-—-cheat-sheet" aria-label="Permalink to &quot;Chapter 65 — Cheat Sheet&quot;">​</a></h1><blockquote><p><em>&quot;Your quick reference for all essential Vim commands.&quot;</em></p></blockquote><hr><p><strong>Difficulty:</strong> ⭐ All levels <strong>Estimated Reading Time:</strong> 10 minutes (reference)</p><hr><h1 id="introduction" tabindex="-1">Introduction <a class="header-anchor" href="#introduction" aria-label="Permalink to &quot;Introduction&quot;">​</a></h1><p>This is a quick reference for the most important Vim commands.</p><p>Use it as a lookup when you forget a command.</p><hr><h1 id="cursor-movement" tabindex="-1">Cursor Movement <a class="header-anchor" href="#cursor-movement" aria-label="Permalink to &quot;Cursor Movement&quot;">​</a></h1><table tabindex="0"><thead><tr><th>Key</th><th>Action</th></tr></thead><tbody><tr><td><code>h</code></td><td>Left</td></tr><tr><td><code>j</code></td><td>Down</td></tr><tr><td><code>k</code></td><td>Up</td></tr><tr><td><code>l</code></td><td>Right</td></tr><tr><td><code>w</code></td><td>Next word</td></tr><tr><td><code>b</code></td><td>Previous word</td></tr><tr><td><code>e</code></td><td>End of word</td></tr><tr><td><code>0</code></td><td>Start of line</td></tr><tr><td><code>$</code></td><td>End of line</td></tr><tr><td><code>^</code></td><td>First non-blank</td></tr><tr><td><code>gg</code></td><td>First line</td></tr><tr><td><code>G</code></td><td>Last line</td></tr><tr><td><code>{line}G</code></td><td>Specific line</td></tr></tbody></table><hr><h1 id="editing" tabindex="-1">Editing <a class="header-anchor" href="#editing" aria-label="Permalink to &quot;Editing&quot;">​</a></h1><table tabindex="0"><thead><tr><th>Key</th><th>Action</th></tr></thead><tbody><tr><td><code>i</code></td><td>Insert before cursor</td></tr><tr><td><code>a</code></td><td>Append after cursor</td></tr><tr><td><code>I</code></td><td>Insert at line start</td></tr><tr><td><code>A</code></td><td>Append at line end</td></tr><tr><td><code>o</code></td><td>Open line below</td></tr><tr><td><code>O</code></td><td>Open line above</td></tr><tr><td><code>dd</code></td><td>Delete line</td></tr><tr><td><code>dw</code></td><td>Delete word</td></tr><tr><td><code>D</code></td><td>Delete to end of line</td></tr><tr><td><code>cc</code></td><td>Change line</td></tr><tr><td><code>cw</code></td><td>Change word</td></tr><tr><td><code>C</code></td><td>Change to end of line</td></tr><tr><td><code>x</code></td><td>Delete character</td></tr><tr><td><code>r</code></td><td>Replace character</td></tr><tr><td><code>.</code></td><td>Repeat last change</td></tr><tr><td><code>u</code></td><td>Undo</td></tr><tr><td><code>Ctrl+r</code></td><td>Redo</td></tr></tbody></table><hr><h1 id="text-objects" tabindex="-1">Text Objects <a class="header-anchor" href="#text-objects" aria-label="Permalink to &quot;Text Objects&quot;">​</a></h1><table tabindex="0"><thead><tr><th>Key</th><th>Action</th></tr></thead><tbody><tr><td><code>ciw</code></td><td>Change inner word</td></tr><tr><td><code>ci(</code></td><td>Change inside parentheses</td></tr><tr><td><code>ci{</code></td><td>Change inside braces</td></tr><tr><td><code>ci&quot;</code></td><td>Change inside quotes</td></tr><tr><td><code>ci&#39;</code></td><td>Change inside single quotes</td></tr><tr><td><code>ci[</code></td><td>Change inside brackets</td></tr><tr><td><code>ci&lt;</code></td><td>Change inside angle brackets</td></tr><tr><td><code>cit</code></td><td>Change inside HTML tag</td></tr><tr><td><code>diw</code></td><td>Delete inner word</td></tr><tr><td><code>daw</code></td><td>Delete a word</td></tr></tbody></table><hr><h1 id="copy-and-paste" tabindex="-1">Copy and Paste <a class="header-anchor" href="#copy-and-paste" aria-label="Permalink to &quot;Copy and Paste&quot;">​</a></h1><table tabindex="0"><thead><tr><th>Key</th><th>Action</th></tr></thead><tbody><tr><td><code>yy</code></td><td>Yank line</td></tr><tr><td><code>yw</code></td><td>Yank word</td></tr><tr><td><code>y$</code></td><td>Yank to end of line</td></tr><tr><td><code>yG</code></td><td>Yank to end of file</td></tr><tr><td><code>p</code></td><td>Paste after cursor</td></tr><tr><td><code>P</code></td><td>Paste before cursor</td></tr><tr><td><code>&quot;ayy</code></td><td>Yank to register a</td></tr><tr><td><code>&quot;ap</code></td><td>Paste from register a</td></tr></tbody></table><hr><h1 id="visual-mode" tabindex="-1">Visual Mode <a class="header-anchor" href="#visual-mode" aria-label="Permalink to &quot;Visual Mode&quot;">​</a></h1><table tabindex="0"><thead><tr><th>Key</th><th>Action</th></tr></thead><tbody><tr><td><code>v</code></td><td>Character visual mode</td></tr><tr><td><code>V</code></td><td>Line visual mode</td></tr><tr><td><code>Ctrl+v</code></td><td>Block visual mode</td></tr><tr><td><code>d</code></td><td>Delete selection</td></tr><tr><td><code>y</code></td><td>Yank selection</td></tr><tr><td><code>c</code></td><td>Change selection</td></tr><tr><td><code>&gt;</code></td><td>Indent right</td></tr><tr><td><code>&lt;</code></td><td>Indent left</td></tr></tbody></table><hr><h1 id="search-and-replace" tabindex="-1">Search and Replace <a class="header-anchor" href="#search-and-replace" aria-label="Permalink to &quot;Search and Replace&quot;">​</a></h1><table tabindex="0"><thead><tr><th>Key/Command</th><th>Action</th></tr></thead><tbody><tr><td><code>/pattern</code></td><td>Search forward</td></tr><tr><td><code>?pattern</code></td><td>Search backward</td></tr><tr><td><code>n</code></td><td>Next match</td></tr><tr><td><code>N</code></td><td>Previous match</td></tr><tr><td><code>*</code></td><td>Search word under cursor</td></tr><tr><td><code>:s/old/new/g</code></td><td>Replace on line</td></tr><tr><td><code>:%s/old/new/g</code></td><td>Replace in file</td></tr><tr><td><code>:%s/old/new/gc</code></td><td>Replace with confirm</td></tr></tbody></table><hr><h1 id="windows-and-tabs" tabindex="-1">Windows and Tabs <a class="header-anchor" href="#windows-and-tabs" aria-label="Permalink to &quot;Windows and Tabs&quot;">​</a></h1><table tabindex="0"><thead><tr><th>Key/Command</th><th>Action</th></tr></thead><tbody><tr><td><code>:split</code></td><td>Horizontal split</td></tr><tr><td><code>:vsplit</code></td><td>Vertical split</td></tr><tr><td><code>Ctrl+w w</code></td><td>Next window</td></tr><tr><td><code>Ctrl+w h/j/k/l</code></td><td>Navigate windows</td></tr><tr><td><code>:tabnew</code></td><td>New tab</td></tr><tr><td><code>gt</code></td><td>Next tab</td></tr><tr><td><code>gT</code></td><td>Previous tab</td></tr></tbody></table><hr><h1 id="file-operations" tabindex="-1">File Operations <a class="header-anchor" href="#file-operations" aria-label="Permalink to &quot;File Operations&quot;">​</a></h1><table tabindex="0"><thead><tr><th>Command</th><th>Action</th></tr></thead><tbody><tr><td><code>:e file</code></td><td>Open file</td></tr><tr><td><code>:w</code></td><td>Save</td></tr><tr><td><code>:q</code></td><td>Quit</td></tr><tr><td><code>:wq</code></td><td>Save and quit</td></tr><tr><td><code>:q!</code></td><td>Force quit</td></tr><tr><td><code>ZZ</code></td><td>Save and quit</td></tr><tr><td><code>ZQ</code></td><td>Quit without saving</td></tr></tbody></table><hr><h1 id="chapter-summary" tabindex="-1">Chapter Summary <a class="header-anchor" href="#chapter-summary" aria-label="Permalink to &quot;Chapter Summary&quot;">​</a></h1><p>This cheat sheet covers the essential Vim commands.</p><p>Bookmark this chapter for quick reference.</p><hr><h2 id="final-words" tabindex="-1">Final Words <a class="header-anchor" href="#final-words" aria-label="Permalink to &quot;Final Words&quot;">​</a></h2><p>Congratulations on completing this handbook!</p><p>You now have the knowledge to use Vim and Neovim effectively.</p><p>Remember:</p><ol><li><strong>Practice daily</strong> — even 10 minutes helps.</li><li><strong>Learn gradually</strong> — add a few commands each week.</li><li><strong>Stay consistent</strong> — muscle memory takes time.</li><li><strong>Use cheat sheets</strong> — reference this chapter whenever you forget.</li><li><strong>Enjoy the journey</strong> — Vim is a tool that keeps rewarding you.</li></ol><p>Happy editing!</p><hr><p><strong><a href="./../">Back to Home</a></strong></p>',45)])])}const u=d(a,[["render",c]]);export{b as __pageData,u as default};
